class Solution {
    public String solveEquation(String equation) {
        String[] parts = equation.split("=");
        int[] left = calculate(parts[0]);
        int[] right = calculate(parts[1]);
        int a = left[0] - right[0];
        int b = right[1] - left[1];
        if (a == 0) {
            if (b == 0) return "Infinite solutions";
            else return "No solution";
        }
        int x = b / a;
        return "x=" + x;
    }

    private int[] calculate(String s) {
        int coefficient = 0, constant = 0;
        int sign = 1;
        int num = 0;
        boolean hasX = false;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (Character.isDigit(c)) {
                num = num * 10 + c - '0';
            } else if (c == 'x') {
                if (num == 0 && !hasX) num = 1;
                coefficient += sign * num;
                num = 0;
                hasX = true;
            } else if (c == '+') {
                constant += sign * num;
                num = 0;
                sign = 1;
                hasX = false;
            } else if (c == '-') {
                constant += sign * num;
                num = 0;
                sign = -1;
                hasX = false;
            }
        }
        constant += sign * num;
        return new int[] {coefficient, constant};
    }
}
